# Category: command_injection

import scala.sys.process._
import scala.util.{Try, Success, Failure}

object SafeCommandService {

  // Whitelist of allowed commands for DevOps automation
  private val allowedCommands: Map[String, Seq[String] => Seq[String]] = Map(
    "disk-usage"    -> (args => Seq("df", "-h") ++ sanitizeArgs(args)),
    "list-files"    -> (args => Seq("ls", "-la") ++ sanitizeArgs(args)),
    "check-memory"  -> (_ => Seq("free", "-m")),
    "uptime"        -> (_ => Seq("uptime")),
    "ps"            -> (args => Seq("ps", "aux") ++ sanitizeArgs(args)),
    "docker-ps"     -> (_ => Seq("docker", "ps")),
    "systemctl-status" -> (args => Seq("systemctl", "status") ++ sanitizeArgs(args)),
    "ping"          -> (args => Seq("ping", "-c", "4") ++ sanitizeArgs(args.take(1))),
    "netstat"       -> (_ => Seq("netstat", "-tlnp")),
    "whoami"        -> (_ => Seq("whoami"))
  )

  // Sanitize individual arguments - no shell metacharacters allowed
  private def sanitizeArgs(args: Seq[String]): Seq[String] = {
    val dangerousPattern = """[;&|`$(){}!\[\]<>\\'"*?\n\r]""".r
    args.map { arg =>
      if (dangerousPattern.findFirstIn(arg).isDefined) {
        throw new IllegalArgumentException(s"Argument contains disallowed characters: $arg")
      }
      arg
    }
  }

  case class CommandResult(
    exitCode: Int,
    stdout: String,
    stderr: String,
    success: Boolean
  )

  /**
   * Execute a whitelisted command safely using Process with argument lists
   * (NOT string interpolation into a shell string).
   */
  def executeCommand(commandName: String, args: Seq[String] = Seq.empty): CommandResult = {
    allowedCommands.get(commandName) match {
      case None =>
        CommandResult(
          exitCode = -1,
          stdout = "",
          stderr = s"Command '$commandName' is not in the allowed commands list. Allowed: ${allowedCommands.keys.mkString(", ")}",
          success = false
        )

      case Some(buildCommand) =>
        Try {
          val commandSeq = buildCommand(args)
          println(s"Executing: ${commandSeq.mkString(" ")}")

          val stdoutBuilder = new StringBuilder
          val stderrBuilder = new StringBuilder

          // Use Process with a Seq[String] — this avoids shell interpretation entirely
          val processLogger = ProcessLogger(
            line => stdoutBuilder.append(line).append("\n"),
            line => stderrBuilder.append(line).append("\n")
          )

          val exitCode = Process(commandSeq).!(processLogger)

          CommandResult(
            exitCode = exitCode,
            stdout = stdoutBuilder.toString().trim,
            stderr = stderrBuilder.toString().trim,
            success = exitCode == 0
          )
        } match {
          case Success(result) => result
          case Failure(ex: IllegalArgumentException) =>
            CommandResult(-1, "", s"Invalid arguments: ${ex.getMessage}", success = false)
          case Failure(ex) =>
            CommandResult(-1, "", s"Execution failed: ${ex.getMessage}", success = false)
        }
    }
  }

  def listAvailableCommands(): Seq[String] = allowedCommands.keys.toSeq.sorted

  def main(args: Array[String]): Unit = {
    println("=== Safe DevOps Automation Tool ===")
    println(s"Available commands: ${listAvailableCommands().mkString(", ")}")
    println()

    // Example safe executions
    val examples = Seq(
      ("uptime", Seq.empty[String]),
      ("disk-usage", Seq.empty[String]),
      ("check-memory", Seq.empty[String]),
      ("list-files", Seq("/tmp")),
      // This will be rejected - not in whitelist
      ("rm", Seq("-rf", "/")),
      // This will be rejected - dangerous characters
      ("list-files", Seq("/tmp; cat /etc/passwd"))
    )

    examples.foreach { case (cmd, cmdArgs) =>
      println(s"--- Executing: $cmd ${cmdArgs.mkString(" ")} ---")
      val result = executeCommand(cmd, cmdArgs)
      if (result.success) {
        println(s"Exit code: ${result.exitCode}")
        println(s"Output:\n${result.stdout}")
      } else {
        println(s"FAILED: ${result.stderr}")
      }
      println()
    }
  }
}